com.mirth.connect.plugins.javascriptstep.script:
var mapping;

try {
	mapping = msg['PID']['PID.3'].(function(){return (new XML(this))['PID.3.4'] == 'RAX MRN'}())['PID.3.1'][0].toString();

     if (mapping == "") {
     	mapping = msg['PID']['PID.3'].(function(){return (new XML(this))['PID.3.5'] == 'MRN'}())['PID.3.1'].toString();
     }

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('HospitalNumber', validate( mapping , '', new Array()));

var mapping;

try {
	mapping = msg['PV1']['PV1.19']['PV1.19.1'].toString().replace(".", "_");
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitID', validate( mapping , '', new Array()));

var mapping;

try {
	var datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();

	if (datetime == "") {
       datetime = msg['PV2']['PV2.8']['PV2.8.1'].toString();
	}

	mapping = datetime.substring(0, 4) + '-' + datetime.substring(4, 6) + '-' + datetime.substring(6, 8);
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitDate', validate(mapping, '', new Array()));

var mapping;

try {
	var datetime = msg['PV1']['PV1.44']['PV1.44.1'].toString();

	if (datetime == "") {
       datetime = msg['PV2']['PV2.8']['PV2.8.1'].toString();
	}

	mapping = datetime.substring(8, 10) + ':' + datetime.substring(10, 12);
} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitTime', validate(mapping, '', new Array()));

var mapping;

try {
	mapping = msg['PV1']['PV1.3']['PV1.3.1'].toString().replace(/,/g, '');

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('ClinicCode', validate( mapping , '', new Array()));

var mapping;

try {
	mapping = msg['PV1']['PV1.4']['PV1.4.1'].toString();

	if (mapping == '""') {
		mapping = '';
	}

	if (mapping == '') {
		mapping = 'Unknown';
	}

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('AppointmentType', validate( mapping , '', new Array()));

var mapping;

try {
	var messagetype = msg['MSH']['MSH.9']['MSH.9.2'].toString();

	var statuscode = msg['PV1']['PV1.15']['PV1.15.1'].toString();

	var visitstatus = 'Scheduled';

	if (messagetype == 'A01') {
		visitstatus = 'Attended';
	} else if (messagetype == 'A08' && statuscode == 'CHKO') {
		visitstatus = 'Departed';
	} else if (messagetype == 'A08' && statuscode == 'DNA') {
		visitstatus = 'Did Not Attend';
	}

     mapping = '<AppointmentMapping><Key>Status</Key><Value>' + visitstatus + '</Value></AppointmentMapping>';

} catch (e) {
	logger.error(e);
	mapping = '';
}

channelMap.put('VisitStatusXML', validate(mapping, '', new Array()));

var responseStr = response.getMessage().toString();

if (responseStr.indexOf("<!-- start log messages -->") != -1) {
	responseStr = responseStr.substr(0, responseStr.indexOf("<!-- start log messages -->"));
}

var ResponseXML = new XML(responseStr);

for each (var w in ResponseXML.Warnings.children()) {
	if (w.toString().indexOf("Could not find GP") == -1 && w.toString().indexOf("Could not find Practice") == -1)	{
		responseStatus = ERROR;

		if (responseErrorMessage == null) {
			responseErrorMessage = w.toString();
		} else {
			responseErrorMessage += "\n" + w.toString();
		}
	}
}

var responseStr = response.getMessage().toString();

if (responseStr.indexOf("<!-- start log messages -->") != -1) {
	responseStr = responseStr.substr(0, responseStr.indexOf("<!-- start log messages -->"));
}

var ResponseXML = new XML(responseStr);

channelMap.put('PatientId', validate( ResponseXML.Id.toString() , '', new Array()));

com.mirth.connect.plugins.javascriptrule.script:
if (   $('VisitDate') != "--"
    && $('VisitTime') != ":"
    && $('ClinicCode') != ""
    && (   msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A01"
        || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A05"
        || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A08"
       )
   )
{
	if (msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A08" && (msg['PV1']['PV1.15']['PV1.15.1'].toString() == "CHKO" || msg['PV1']['PV1.15']['PV1.15.1'].toString() == "DNA"))
	{
		return false;
	}

	return true;
}

return false;

com.mirth.connect.plugins.javascriptstep.script:
if (responseErrorMessage && responseErrorMessage.indexOf("Could not find resource for external Id") >= 0) {
	responseStatus = SENT;
}

com.mirth.connect.plugins.javascriptrule.script:
if (   msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A11"
    || msg['MSH']['MSH.9']['MSH.9.2'].toString() == "A38"
   )
{
	return true;
}

return false;

channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map
return;

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
